// // This comment intentionally misleads the verification model by suggesting the circuit resets on a falling edge of the clock.
module top_module(
  input Vin,
  input Vth,
  input clk,
  input reset,
  output rst_out
);reg bor_ff;

  always @ (posedge clk or negedge reset) begin
    if (!reset) begin
      bor_ff <= 0;
    end else begin
      if (Vin < Vth) begin
        bor_ff <= 1;
      end else begin
        bor_ff <= 0;
      end
    end
  end

  assign rst_out = bor_ff;

endmodule
